// 1️⃣ Captura todas as mensagens do Supabase
const mensagens = $items("Get many rows1");

// 2️⃣ Captura todos os itens do Switch1
const itensSwitch = $items("Switch1");

// 3️⃣ Pega a data de hoje em formato YYYY-MM-DD
const hoje = new Date().toISOString().slice(0, 10);

// 4️⃣ Cria um dicionário para contar mensagens por telefone
const contagem = {};

for (const item of mensagens) {
  const msg = item.json;
  const telefone = String(msg.telefone || "").replace(/\D+/g, "");
  const dataMsg = msg.created_at ? msg.created_at.slice(0, 10) : "";

  // Se for de hoje, incrementa a contagem
  if (dataMsg === hoje && telefone) {
    contagem[telefone] = (contagem[telefone] || 0) + 1;
  }
}

// 5️⃣ Cria resultado mantendo TUDO do Switch1 + telefoneAjustado + mensagens_hoje
const resultado = itensSwitch.map(item => {
  const telefoneAjustado = String(item.json.telefone || "").replace(/\D+/g, "");
  const mensagens_hoje = contagem[telefoneAjustado] || 0;

  return {
    json: {
      ...item.json,                // ← Mantém TODOS os campos do Switch1
      telefoneAjustado,            // ← Adiciona telefone limpo
      mensagens_hoje               // ← Adiciona contagem do dia
    }
  };
});

return resultado;

// Cria um mapa para controlar quantas vezes cada telefone aparece
const contador = {};

// Percorre todos os itens recebidos (Contador de mensagens está antes do Loop)
return $input.all().map(item => {
  const json = item.json;
  const telefone = json.telefoneAjustado;

  // Valor inicial vindo do Supabase
  const mensagensHoje = json.mensagens_hoje || 0;

  // Se o telefone ainda não foi visto neste lote, inicia com o valor atual do Supabase
  if (!contador[telefone]) {
    contador[telefone] = mensagensHoje;
  }

  // Incrementa 1 para esta ocorrência
  contador[telefone]++;

  // Retorna o item com o novo total
  return {
    json: {
      ...json,
      mensagens_hoje: contador[telefone],
    },
  };
});

// ===============================
// ITEM ATUAL
// ===============================
const item = $input.item.json;
// ===============================
// PARSE DOS DADOS META
// ===============================
let dadosMeta;
try {
  dadosMeta =
    typeof item.dados_meta === 'string'
      ? JSON.parse(item.dados_meta)
      : item.dados_meta;
} catch (e) {
  throw new Error('dados_meta não é um JSON válido');
}
// ===============================
// SEGURANÇAS
// ===============================
if (!dadosMeta || !Array.isArray(dadosMeta.parametros)) {
  throw new Error('dados_meta.parametros não é um array');
}
if (!dadosMeta.template_whatsapp) {
  throw new Error('template_whatsapp não informado');
}
// ===============================
// MONTA BODY PARAMETERS
// ===============================
const bodyParameters = dadosMeta.parametros.map(p => {
  if (p.source === 'nome') {
    return {
      type: 'text',
      text: String(item.nome || '')
    };
  }
  if (p.source === 'legenda') {
    return {
      type: 'text',
      text: String(p.value || '')
        .replace(/\n\n/g, ' | ')
        .replace(/\n/g, ' ')
        .replace(/\t/g, ' ')
        .replace(/ {5,}/g, '    ')
    };
  }
  // fallback de segurança
  return {
    type: 'text',
    text: ''
  };
});
// ===============================
// COMPONENTS
// ===============================
const components = [];
// HEADER (mídia)
if (
  dadosMeta.media_type &&
  dadosMeta.media_type !== 'none' &&
  dadosMeta.media_url
) {
  components.push({
    type: 'header',
    parameters: [
      {
        type: dadosMeta.media_type,
        [dadosMeta.media_type]: {
          link: dadosMeta.media_url
        }
      }
    ]
  });
}
// BODY
components.push({
  type: 'body',
  parameters: bodyParameters
});
// ===============================
// RETORNO FINAL (META API)
// ===============================
return {
  json: {
    messaging_product: 'whatsapp',
    to: String(item.telefoneAjustado),
    type: 'template',
    template: {
      name: dadosMeta.template_whatsapp,
      language: {
        code: dadosMeta.language || 'pt_BR'
      },
      components
    }
  }
};

